19	/// Filter that limits Kanata output to a window around a specific loop body.
20	/// The logger stays disabled until `skip_iters` retires of `end_pc` have been
21	/// observed, then records `record_iters` more retires of `end_pc` and exits.
22	struct LoopGate
23	{
24	  uint64_t start_pc;     ///< informational; reported in summary line
25	  uint64_t end_pc;       ///< retire of this PC advances the iteration counter
26	  uint64_t skip_iters;   ///< pre-warmup iterations to ignore
27	  uint64_t record_iters; ///< iterations to record before exit
28	};
29	
30	/// Maps arbitrary keys to sequential uint64_t IDs.
31	/// Port of Python SequentialIndexMap from tools/utils.py.
32	class SequentialIndexMap
33	{
34	public:
35	  explicit SequentialIndexMap(uint64_t start_idx = 0)
36	      : idx_(start_idx)
37	  {}
38	
39	  uint64_t update(uint64_t key)
40	  {
41	    auto tmp = idx_;
42	    key2id_[key] = idx_++;
43	    return tmp;
44	  }
45	
46	  uint64_t get(uint64_t key) const { return key2id_.at(key); }
47	
48	  uint64_t pop(uint64_t key)
49	  {
50	    auto it = key2id_.find(key);
51	    auto val = it->second;
52	    key2id_.erase(it);
53	    return val;
54	  }
55	
56	  bool contains(uint64_t key) const { return key2id_.count(key) != 0; }
57	
58	private:
59	  std::unordered_map<uint64_t, uint64_t> key2id_;
60	  uint64_t idx_;
61	};
