63	/// Writes Kanata pipeline visualization format.
64	/// Port of Python KanataLogger from tools/utils.py.
65	///
66	/// Format reference:
67	/// https://github.com/shioyadan/Konata/blob/master/docs/kanata-log-format.md
68	class KanataLogger
69	{
70	public:
71	  /// File-based output (existing behavior).
72	  explicit KanataLogger(const std::string& filename,
73	                        std::optional<LoopGate> gate = std::nullopt)
74	      : gate_(gate)
75	      , enabled_(!gate_.has_value() || gate_->skip_iters == 0)
76	  {
77	    owned_file_.open(filename);
78	    if (!owned_file_.is_open()) {
79	      spdlog::critical("Failed to open kanata log file: {}", filename);
80	      return;
81	    }
82	    output_ = &owned_file_;
83	    write_header();
84	    spdlog::info("Writing kanata pipeline log to {}", filename);
85	    if (gate_)
86	      spdlog::info(
87	        "Kanata loop gate: start={:#x} end={:#x} skip={} record={}",
88	        gate_->start_pc, gate_->end_pc, gate_->skip_iters,
89	        gate_->record_iters);
90	  }
91	
92	  /// Stream-based output (caller owns the ostream lifetime).
93	  explicit KanataLogger(std::ostream& os,
94	                        std::optional<LoopGate> gate = std::nullopt)
95	      : output_(&os)
96	      , gate_(gate)
97	      , enabled_(!gate_.has_value() || gate_->skip_iters == 0)
98	  {
99	    write_header();
100	  }
101	
102	  ~KanataLogger() { flush_all(); }
103	
104	  KanataLogger(const KanataLogger&) = delete;
105	  KanataLogger& operator=(const KanataLogger&) = delete;
106	
107	  void advance_cycle(int cycles)
108	  {
109	    total_cycles_ += static_cast<uint64_t>(cycles);
110	    if (enabled_)
111	      *output_ << "C\t" << cycles << '\n';
112	  }
113	
114	  void start_insn(uint64_t pc, uint64_t id)
115	  {
116	    id_to_pc_[id] = pc;
117	    if (!enabled_)
118	      return;
119	    inflight_.insert(id);
120	    *output_ << fmt::format("I\t{}\t{}\t0\n", id, id);
121	    auto it = code_map_.find(pc);
122	    auto code = (it != code_map_.end()) ? it->second : std::string{};
123	    *output_ << fmt::format("L\t{}\t0\t{:#x}: {}\n", id, pc, code);
124	  }
125	
126	  /// Start instruction without PC (OoO: PC unknown at issue time).
127	  /// Use label_insn() later to back-fill the PC at commit.
128	  void start_insn_deferred(uint64_t id)
129	  {
130	    if (!enabled_)
131	      return;
132	    inflight_.insert(id);
133	    *output_ << fmt::format("I\t{}\t{}\t0\n", id, id);
134	  }
135	
136	  /// Back-fill label for a deferred instruction (OoO commit).
137	  void label_insn(uint64_t id, uint64_t pc,
138	                  std::string_view suffix = "")
139	  {
140	    id_to_pc_[id] = pc;
141	    if (!is_inflight(id))
142	      return;
143	    auto it = code_map_.find(pc);
144	    auto code = (it != code_map_.end()) ? it->second : std::string{};
145	    if (suffix.empty())
146	      *output_ << fmt::format("L\t{}\t0\t{:#x}: {}\n", id, pc, code);
147	    else
148	      *output_ << fmt::format("L\t{}\t0\t{:#x}: {} [{}]\n", id, pc, code,
149	                              suffix);
150	  }
151	
152	  void retire_insn(uint64_t id)
153	  {
154	    bool emitted = false;
155	    if (remove_inflight(id)) {
156	      *output_ << fmt::format("R\t{}\t{}\t0\n", id, id);
157	      ++recorded_insns_;
158	      emitted = true;
159	    }
160	    on_retire_pc(id, emitted);
161	  }
162	
163	  void flush_insn(uint64_t id)
164	  {
165	    if (remove_inflight(id))
166	      *output_ << fmt::format("R\t{}\t0\t1\n", id);
167	    id_to_pc_.erase(id);
168	  }
169	
170	  void stage_insn(uint64_t id, std::string_view stage_name, int lane_id = 0)
171	  {
172	    if (is_inflight(id))
173	      *output_ << fmt::format("S\t{}\t{}\t{}\n", id, lane_id, stage_name);
174	  }
175	
176	  void end_stage_insn(uint64_t id, std::string_view stage_name)
177	  {
178	    if (is_inflight(id))
179	      *output_ << fmt::format("E\t{}\t0\t{}\n", id, stage_name);
180	  }
181	
182	  void comment_insn(uint64_t id, std::string_view msg)
183	  {
184	    if (is_inflight(id))
185	      *output_ << fmt::format("L\t{}\t1\t{}\n", id, msg);
186	  }
187	
188	  void flush_all()
189	  {
190	    for (auto id: inflight_)
191	      *output_ << fmt::format("R\t{}\t0\t1\n", id);
192	    inflight_.clear();
193	    output_->flush();
194	  }
195	
196	  /// Load objdump -d output to populate PC→assembly map.
197	  void load_objdump(const std::string& filename)
198	  {
199	    std::ifstream fin(filename);
200	    if (!fin.is_open()) {
201	      spdlog::warn("Failed to open objdump file: {}", filename);
202	      return;
203	    }
204	    std::regex code_regex(R"(^\s*([0-9a-f]+):\t([0-9a-f ]+)\t(.+)$)");
205	    std::string line;
206	    while (std::getline(fin, line)) {
207	      std::smatch match;
208	      if (std::regex_match(line, match, code_regex)) {
209	        auto pc = std::stoull(match[1].str(), nullptr, 16);
210	        auto asm_code = match[3].str();
211	        // Replace tabs with double spaces (same as Python)
212	        for (auto pos = asm_code.find('\t'); pos != std::string::npos;
213	             pos = asm_code.find('\t', pos))
214	        {
215	          asm_code.replace(pos, 1, "  ");
216	          pos += 2;
217	        }
218	        code_map_[pc] = std::move(asm_code);
219	      }
220	    }
221	    spdlog::info("Loaded {} disassembly entries from {}", code_map_.size(),
222	                 filename);
223	  }
224	
225	  bool is_open() const { return output_ != nullptr; }
226	
227	private:
228	  bool is_inflight(uint64_t id) const { return inflight_.count(id) != 0; }
229	
230	  bool remove_inflight(uint64_t id) { return inflight_.erase(id) > 0; }
231	
232	  void write_header()
233	  {
234	    *output_ << "Kanata\t0004\n";
235	    *output_ << "C=\t0\n";
236	  }
237	
238	  /// Called from retire_insn(). Looks up the PC for `id`, advances the
239	  /// iteration counter when it matches the gate's end_pc, and handles the
240	  /// enable / exit transitions.
241	  void on_retire_pc(uint64_t id, bool /*emitted*/)
242	  {
243	    if (!gate_) {
244	      id_to_pc_.erase(id);
245	      return;
246	    }
247	    auto it = id_to_pc_.find(id);
248	    if (it == id_to_pc_.end())
249	      return;
250	    auto pc = it->second;
251	    id_to_pc_.erase(it);
252	    if (pc != gate_->end_pc)
253	      return;
254	
255	    ++end_retired_;
256	    if (!enabled_ && end_retired_ == gate_->skip_iters) {
257	      enabled_ = true;
258	      start_cycle_ = total_cycles_;
259	      spdlog::info(
260	        "Kanata loop gate: warmup done at cycle {}, recording {} iters",
261	        total_cycles_, gate_->record_iters);
262	    } else if (enabled_
263	               && end_retired_ == gate_->skip_iters + gate_->record_iters) {
264	      auto window_cycles = total_cycles_ - start_cycle_;
265	      spdlog::info(
266	        "Kanata loop window [pc {:#x}..{:#x}]: {} iters, {} insns, {} "
267	        "cycles, IPC={:.3f}",
268	        gate_->start_pc, gate_->end_pc, gate_->record_iters,
269	        recorded_insns_, window_cycles,
270	        window_cycles ? double(recorded_insns_) / double(window_cycles)
271	                      : 0.0);
272	      flush_all();
273	      std::exit(0);
274	    }
275	  }
276	
277	  std::ostream* output_ = nullptr;
278	  std::ofstream owned_file_;
279	  std::unordered_map<uint64_t, std::string> code_map_;
280	  std::unordered_set<uint64_t> inflight_;
281	
282	  std::optional<LoopGate> gate_;
283	  std::unordered_map<uint64_t, uint64_t> id_to_pc_;
284	  bool enabled_ = true;
285	  uint64_t end_retired_ = 0;
286	  uint64_t total_cycles_ = 0;
287	  uint64_t start_cycle_ = 0;
288	  uint64_t recorded_insns_ = 0;
289	};
290	
291	} // namespace kanata
