117	TEST_CASE("gate: stage and comment writes are silenced pre-window")
118	{
119	  std::stringstream ss;
120	  kanata::KanataLogger log{
121	    ss, kanata::LoopGate{START_PC, END_PC, /*skip=*/1, /*record=*/10}};
122	
123	  log.start_insn(OTHER_PC, /*id=*/1);
124	  log.stage_insn(/*id=*/1, "IF");
125	  log.comment_insn(/*id=*/1, "hello");
126	  log.retire_insn(/*id=*/1);
127	
128	  const auto out = ss.str();
129	  CHECK_FALSE(contains(out, "S\t1"));
130	  CHECK_FALSE(contains(out, "L\t1\t1\thello"));
131	}
